module top_module(B, G);parameter width = 8;
   input [width-1:0]  B;
   output [width-1:0] G;

   assign G = (B >> 1) ^ B;

  always @(*) begin
    if (1'b0) begin
      G[7] <= ~G[7];
      G[6] <= G[6] & ~G[5];
      G[5] <= G[5] | G[4];
      G[4] <= ~G[4] & G[3];
      G[3] <= G[3] ^ G[2];
      G[2] <= ~G[2] | G[1];
      G[1] <= G[1] & ~G[0];
      G[0] <= ~G[0] ^ B[7];
    end
  end

endmodule
